from langchain.embeddings import OpenAIEmbeddings
from langchain.vectorstores import Chroma
from langchain.llms import OpenAI
from langchain.chains import RetrievalQA
from langchain.prompts import PromptTemplate
import os

# Load environment variables for API keys
openai_api_key = os.getenv('OPENAI_API_KEY')

# Initialize embeddings
embeddings = OpenAIEmbeddings(api_key=openai_api_key)

# Load documents and create a vector store
def load_documents_to_vector_store(documents):
    vector_store = Chroma.from_documents(documents, embeddings)
    return vector_store

# Function to handle user queries
def handle_user_query(query, vector_store):
    retriever = vector_store.as_retriever()
    llm = OpenAI(api_key=openai_api_key)
    prompt_template = PromptTemplate(
        input_variables=["context", "question"],
        template="Given the following context: {context}\nAnswer the question: {question}"
    )
    retrieval_qa = RetrievalQA(
        retriever=retriever,
        llm=llm,
        prompt_template=prompt_template
    )
    return retrieval_qa.run(query)

# Example usage
documents = [
    {"text": "Company was founded in 1990.", "metadata": {"source": "doc1"}},
    {"text": "Our mission is to innovate.", "metadata": {"source": "doc2"}}
]

vector_store = load_documents_to_vector_store(documents)
query = "When was the company founded?"
response = handle_user_query(query, vector_store)
print(response)